+function isPlainObject(value: unknown): value is Record<string, unknown> {
+  return !!value && typeof value === "object" && !Array.isArray(value) && Object.getPrototypeOf(value) === Object.prototype;
+}
+
+function kebabToCamelCase(value: string): string {
+  return value.replace(/-([a-z])/g, (_, char) => char.toUpperCase());
+}
+
+function flattenConfig(value: Record<string, unknown>, prefix = ""): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const [key, item] of Object.entries(value)) {
+    const name = kebabToCamelCase(prefix ? `${prefix}.${key}` : key);
+    if (isPlainObject(item)) Object.assign(result, flattenConfig(item, name));
+    else result[name] = item;
+  }
+  return result;
+}
+
+function parseRc(content: string): Record<string, unknown> {
+  const values: Record<string, unknown> = {};
+  for (const line of content.split(/\\r?\
/)) {
+    const trimmed = line.trim();
+    if (!trimmed || trimmed.startsWith("#")) continue;
+    const index = trimmed.indexOf("=");
+    if (index < 1) throw new Error(`Invalid RC entry: ${line}`);
+    const key = kebabToCamelCase(trimmed.slice(0, index).trim());
+    let value = trimmed.slice(index + 1).trim();
+    if (value.startsWith('"')) {
+      if (!value.endsWith('"') || value.length < 2) throw new Error(`Unterminated quoted value: ${line}`);
+      value = value.slice(1, -1);
+    } else if (value === "true") values[key] = true;
+    else if (value === "false") values[key] = false;
+    else if (/^-?(?:\\d+\\.?\\d*|\\.\\d+)$/.test(value)) values[key] = Number(value);
+    else values[key] = value;
+    if (!(key in values)) values[key] = value;
+  }
+  return values;
